// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader !== undefined ? headers[apiKeyHeader] : $input.first().json.api_key;
const expectedKey = $env.BARK_API_KEY;

// Timing-safe comparison - constant time regardless of input length
function timingSafeEqual(a, b) {
  // Both must be strings of same length to proceed
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const maxLen = Math.max(a.length, b.length);
  let result = 0;
  for (let i = 0; i < maxLen; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  return result === 0 && a.length === b.length;
}

if (expectedKey && !timingSafeEqual(providedKey || '', expectedKey)) {
  throw new Error('Authentication failed');
}

const input = $input.first().json || {};
const text = input.text || '';
const voicePreset = input.voice_preset || '';
const outputFormat = input.output_format || '';
const channelRaw = (input.channel || 'general').replace(/^#+/, '').replace(/[<>@&]/g, '').slice(0, 100);

// === TEXT VALIDATION ===
if (!text || text.trim().length === 0) {
  throw new Error('Missing required field: text');
}
if (text.length > 1024) {
  throw new Error('Text too long: max 1024 characters');
}

// === VOICE_PRESET VALIDATION ===
// Allow empty (will use default), but validate if provided
if (voicePreset) {
  const validVoicePattern = /^[a-zA-Z0-9_/-]+$/;
  if (!validVoicePattern.test(voicePreset)) {
    throw new Error('Invalid voice_preset: must be alphanumeric, underscore, slash, or dash only');
  }
  if (voicePreset.length > 50) {
    throw new Error('voice_preset too long: max 50 characters');
  }
}

// === OUTPUT_FORMAT VALIDATION ===
const validFormats = ['wav', 'mp3', 'ogg', 'flac', 'webm'];
const format = (outputFormat || 'wav').toLowerCase();
if (!validFormats.includes(format)) {
  throw new Error('Invalid output_format: must be one of ' + validFormats.join(', '));
}

// === CHANNEL VALIDATION ===
if (!channelRaw.match(/^[a-zA-Z0-9_-]+$/)) {
  throw new Error('Invalid channel: must be alphanumeric, dash, or underscore only');
}
const channel = channelRaw;

return [{
  json: {
    text: text.trim(),
    voice_preset: voicePreset || 'v2/en_speaker_6',
    output_format: format,
    channel: channel
  }
}];

// Process Bark response - merge with original webhook input
// $input.all() provides both Bark API response and Webhook Trigger payload
const allInputs = $input.all();
const barkResponse = allInputs[0]?.json || {};
const validatedInput = $('Validate Input').first().json || {};

const audio_base64 = barkResponse.audio_base64 || '';
const sample_rate = barkResponse.sample_rate || 0;
const format = barkResponse.format || validatedInput.output_format || 'wav';

return [{
  json: {
    success: !!audio_base64,
    format: format,
    sample_rate: sample_rate,
    audio_size_bytes: audio_base64.length,
    timestamp: new Date().toISOString(),
    channel: validatedInput.channel || 'general',
    text: validatedInput.text || '',
    voice_preset: validatedInput.voice_preset || 'v2/en_speaker_6',
    output_format: validatedInput.output_format || 'wav'
  }
}];
